mapper.select:
select ci.target_type, ci.target_id, ci.action_type, rv.title as title, rv.intro as content, ma.url as cover_url, au.nickname as author_nickname, ci.updated_at as interacted_at from cook_content_interactions ci inner join cook_recipes r on r.id = ci.target_id and r.deleted_at is null left join cook_recipe_versions rv on rv.id = r.current_version_id and rv.deleted_at is null left join cook_media_assets ma on ma.id = rv.cover_media_id and ma.deleted_at is null inner join cook_users au on au.id = r.author_id and au.deleted_at is null where ci.user_id = #{userId} and ci.action_type = #{actionType} and ci.status = 'active' and ci.target_type = 'recipe'
and ci.target_type = #{targetType}
union all select ci.target_type, ci.target_id, ci.action_type, concat('动态 #', p.id) as title, p.content as content, ma.url as cover_url, au.nickname as author_nickname, ci.updated_at as interacted_at from cook_content_interactions ci inner join cook_posts p on p.id = ci.target_id and p.deleted_at is null left join cook_media_assets ma on ma.id = cast(json_unquote(json_extract(p.media_ids_json, '$[0]')) as unsigned) and ma.deleted_at is null inner join cook_users au on au.id = p.user_id and au.deleted_at is null where ci.user_id = #{userId} and ci.action_type = #{actionType} and ci.status = 'active' and ci.target_type = 'post'
and ci.target_type = #{targetType}
order by interacted_at desc
